const now = new Date();
if (now.getUTCDay() !== 0) return [];
const tzGroups = ["America/New_York","America/Chicago","America/Denver","America/Los_Angeles","America/Anchorage","Pacific/Honolulu","America/Phoenix"];
const target = [];
for (const tz of tzGroups) { try { const lt = new Date(now.toLocaleString("en-US",{timeZone:tz})); if (lt.getHours()===18) target.push(tz); } catch(e){} }
if (!target.length) return [];
const aliases = {"America/New_York":["America/New_York","US/Eastern","Eastern","EST","EDT","ET"],"America/Chicago":["America/Chicago","US/Central","Central","CST","CDT","CT"],"America/Denver":["America/Denver","US/Mountain","Mountain","MST","MDT","MT"],"America/Los_Angeles":["America/Los_Angeles","US/Pacific","Pacific","PST","PDT","PT"],"America/Anchorage":["America/Anchorage","US/Alaska","Alaska","AKST","AKDT"],"Pacific/Honolulu":["Pacific/Honolulu","US/Hawaii","Hawaii","HST"],"America/Phoenix":["America/Phoenix","US/Arizona","Arizona"]};
let all = [];
for (const tz of target) { if (aliases[tz]) all = all.concat(aliases[tz]); else all.push(tz); }
return {targetTimezones: target, allMatchingTimezones: all, utcHour: now.getUTCHours(), runTime: now.toISOString()};

const clients = .first().json;
const checkData = .first().json;
const matchingTimezones = checkData.allMatchingTimezones || [];
if (!Array.isArray(clients) || !clients.length) return [];
const filtered = clients.filter(c => { const tz = (c.timezone||"America/Chicago").trim(); return matchingTimezones.some(t => t.toLowerCase()===tz.toLowerCase()); });
if (!filtered.length) return [];
return filtered.map(c => ({json: c}));

const callLogs = .first().json;
const client = .first().json;
const logs = Array.isArray(callLogs) ? callLogs : [];
const totalCalls = logs.length;
const leads = logs.filter(l => l.is_lead===true||(l.lead_score&&l.lead_score>=6));
const totalLeads = leads.length;
const totalHotLeads = logs.filter(l=>l.lead_score&&l.lead_score>=8).length;
const totalWarmLeads = logs.filter(l=>l.lead_score&&l.lead_score>=6&&l.lead_score<8).length;
const totalSpam = logs.filter(l=>!l.is_lead&&l.lead_score!==null&&l.lead_score<3).length;
const totalGeneral = logs.filter(l=>!l.is_lead&&l.lead_score>=3&&l.lead_score<6).length;
const avgScore = logs.length>0?(logs.reduce((s,l)=>s+(l.lead_score||0),0)/logs.length).toFixed(1):"0";
const totalDuration = logs.reduce((s,l)=>s+(l.duration_seconds||0),0);
const avgDuration = logs.length>0?Math.round(totalDuration/logs.length):0;
const svcBreakdown = {};
logs.forEach(l=>{const s=l.service_requested||"Other";svcBreakdown[s]=(svcBreakdown[s]||0)+1;});
const weekEnd=new Date(),weekStart=new Date(Date.now()-7*24*60*60*1000);
const fmt=d=>d.toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"});
return {company_name:client.company_name||"Client",agent_name:client.agent_name||"AI Receptionist",lead_email:client.lead_email||"",agent_id:client.agent_id||"",totalCalls,totalLeads,totalHotLeads,totalWarmLeads,totalSpam,totalGeneral,avgScore,totalDuration,avgDuration,serviceBreakdown:svcBreakdown,weekStart:fmt(weekStart),weekEnd:fmt(weekEnd),topLeads:leads.slice(0,5).map(l=>({name:l.caller_name||"Unknown",phone:l.caller_phone||"",service:l.service_requested||"",score:l.lead_score||0}))};

const d = .first().json;
const fmtD = (s) => { if(s<60) return s+"s"; const m=Math.floor(s/60),sec=s%60; return sec>0?m+"m "+sec+"s":m+"m"; };
const emailHtml = "<html><body><h2>Weekly Report: "+d.company_name+"</h2><p>Period: "+d.weekStart+" - "+d.weekEnd+"</p><p>Total Calls: "+d.totalCalls+" | Leads: "+d.totalLeads+" | Hot Leads: "+d.totalHotLeads+"</p></body></html>";
return {emailHtml, lead_email: d.lead_email, company_name: d.company_name, agent_name: d.agent_name, totalCalls: d.totalCalls, totalLeads: d.totalLeads, weekStart: d.weekStart, weekEnd: d.weekEnd};

